import React, { useState } from 'react';
import { LoanData } from '../types/loan';
import FormField from './FormField';
import './LoanForm.css';

interface LoanFormProps {
  onSubmit: (data: LoanData) => void;
}

const LoanForm: React.FC<LoanFormProps> = ({ onSubmit }) => {
  const [formData, setFormData] = useState<LoanData>({
    loan_amount: 1500000, // UAE sample data
    annual_interest_rate: 3.5,
    loan_term_years: 25,
    monthly_extra_payment: 2000
  });

  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const validateField = (name: string, value: number): string => {
    switch (name) {
      case 'loan_amount':
        if (value <= 0) return 'Loan amount must be greater than zero';
        if (value > 10000000) return 'Loan amount cannot exceed $10,000,000';
        return '';

      case 'annual_interest_rate':
        if (value < 0) return 'Interest rate cannot be negative';
        if (value > 30) return 'Interest rate cannot exceed 30%';
        return '';

      case 'loan_term_years':
        if (value <= 0) return 'Loan term must be greater than zero';
        if (value > 50) return 'Loan term cannot exceed 50 years';
        if (!Number.isInteger(value)) return 'Loan term must be a whole number';
        return '';

      case 'monthly_extra_payment':
        if (value < 0) return 'Extra payment cannot be negative';
        if (value > 1000000) return 'Extra payment cannot exceed $1,000,000';
        return '';

      default:
        return '';
    }
  };

  const handleInputChange = (name: string, value: number) => {
    setFormData(prev => ({ ...prev, [name]: value }));

    // Clear error when user starts typing
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const handleInputBlur = (name: string, value: number) => {
    const error = validateField(name, value);
    setErrors(prev => ({ ...prev, [name]: error }));
  };

  const validateForm = (): boolean => {
    const newErrors: { [key: string]: string } = {};

    Object.entries(formData).forEach(([key, value]) => {
      if (key === 'monthly_extra_payment' && !value) return; // Optional field
      const error = validateField(key, value);
      if (error) newErrors[key] = error;
    });

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (validateForm()) {
      onSubmit(formData);
    }
  };

  const loadSampleData = () => {
    const sampleData: LoanData = {
      loan_amount: 1500000, // 1.5M AED
      annual_interest_rate: 3.5,
      loan_term_years: 25,
      monthly_extra_payment: 2000
    };
    setFormData(sampleData);
    setErrors({});
  };

  return (
    <form className="loan-form" onSubmit={handleSubmit}>
      <div className="form-row">
        <FormField
          label="Loan Amount"
          name="loan_amount"
          type="number"
          value={formData.loan_amount}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          error={errors.loan_amount}
          min={1}
          max={10000000}
          step={0.01}
          required
          currency
        />

        <FormField
          label="Annual Interest Rate (%)"
          name="annual_interest_rate"
          type="number"
          value={formData.annual_interest_rate}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          error={errors.annual_interest_rate}
          min={0}
          max={30}
          step={0.001}
          required
        />
      </div>

      <div className="form-row">
        <FormField
          label="Loan Term (Years)"
          name="loan_term_years"
          type="number"
          value={formData.loan_term_years}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          error={errors.loan_term_years}
          min={1}
          max={50}
          required
        />

        <FormField
          label="Monthly Extra Payment"
          name="monthly_extra_payment"
          type="number"
          value={formData.monthly_extra_payment || ''}
          onChange={handleInputChange}
          onBlur={handleInputBlur}
          error={errors.monthly_extra_payment}
          min={0}
          max={1000000}
          step={0.01}
          placeholder="Optional"
          currency
        />
      </div>

      <div className="button-row">
        <button type="button" className="sample-btn" onClick={loadSampleData}>
          Load Sample Data
        </button>
        <button type="submit" className="calculate-btn">
          Calculate Loan
        </button>
      </div>
    </form>
  );
};

export default LoanForm;
